external_knowledge:
- "Comprehensive weather data" includes cloudiness, latitude, longitude, humidity, maximum and minimum temperatures, wind speed, wind direction, pressure, precipitation, visibility, UV index, and weather conditions; 
- "Access information" includes access date, access type, IP address, user agent, and session ID;
- "Past 24 hours" means from the current time minus 24 hours to the current time;
- "Cloudiness over 50%" refers to cloudiness greater than 50%.

sql:
SELECT wd.record_id, wd.timestamp, wd.cloudiness, wd.humidity
FROM weather_data wd
WHERE wd.city_id = 2 AND wd.timestamp BETWEEN '2023-05-01' AND '2023-05-30';
